import React from "react";
import { Link } from "react-router-dom";
import logo from "../../assets/images/logo1.png";
import ApiRequest from '../../Services/ApiRequest';
import { updateSession } from '../../Helpers/Functions';
import authService from '../../Services/auth.service';
import { toasterAlert as toastAlert } from '../../Helpers/Functions';


class EmailVerifySuccess extends React.Component {
    async getUserData() {
        const userDetails = await ApiRequest.getRequest('/userDetails');
        console.log(userDetails);
        if (userDetails && userDetails.status === 200) {
            const data = {
                __userDetail: userDetails.data.user[0]
            }
            updateSession(data);
            authService.userRedirectHandler(userDetails);
            

        } else {
            toastAlert('error', 'Something went wrong please try again!')
        }
    }

    render() {
        setTimeout(
            ()=> this.getUserData(),
            3000
        );
        return (
            <>
                <div className="container-fluid login-wrapper pending-status" >
                    <div className="row mar-width-0 width-wrap">
                        <div className="col-md-12 text-center pt-2 ">
                            <Link to="/"> <img src={logo} alt="" /></Link>
                        </div>
                        <div className="col-md-12 login-heading">
                            <p className="font-family">Make the most of your professional life</p>
                        </div>

                        <div className="row mar-width-0 form-bg">
                            <div className="col-md-12 p-0">
                                <h3>Email Verification</h3>
                                <p className="font-family">Your Email successfully verified</p>

                            </div>
                        </div>


                    </div>
                </div>
            </>
        );
    }
}

export default EmailVerifySuccess